#include <iostream>

int main() {
    constexpr int grid_width = 12;
    constexpr int grid_height = 8;
    constexpr int total_cells = grid_width * grid_height;
    constexpr int border_cells = 2 * grid_width + 2 * (grid_height - 2);

    std::cout << "Grid width: " << grid_width << "\n";
    std::cout << "Grid height: " << grid_height << "\n";
    std::cout << "Total cells: " << total_cells << "\n";
    std::cout << "Border cells: " << border_cells << "\n";
    return 0;
}

