solution_code:
#include <iostream>
#include <iomanip>

double celsiusToFahrenheit(int celsius) {
    constexpr double scale = 9.0 / 5.0;
    constexpr double offset = 32.0;
    return celsius * scale + offset;
}

int main() {
    int c;
    std::cin >> c;
    std::cout << "Fahrenheit: " << std::fixed << std::setprecision(1) << celsiusToFahrenheit(c) << "\n";
    return 0;
}
